static int square(int number) {
    return number * number; // must return an int
}

public class Main {
    static void greet(String name) {
        System.out.println("Hello, " + name + "!");
    }

    public static void main(String[] args) {
        greet("Aman");
    }
}

static void printIfPositive(int number) {
    if (number <= 0) {
        return; // exits early, no value given back
    }
    System.out.println(number);
}

public class Main {
    static String checkAge(int age) {
        if (age < 0) {
            return "Invalid age";
        }
        if (age < 18) {
            return "Minor";
        }
        return "Adult";
    }

    public static void main(String[] args) {
        System.out.println(checkAge(25));
        System.out.println(checkAge(15));
        System.out.println(checkAge(-3));
    }
}

